#include<bits/stdc++.h>
using namespace std;
long long n,dis[1000010],sum[1000010],ans=1,f[1000010];
vector<long long> mp[1000010];
void dfs(long long x,long long fa=-1)
{
    f[1]+=dis[x];
    sum[x]=1;
    for(auto v:mp[x])
    {
        if(v!=fa)
        {
            dis[v]=dis[x]+1;
            dfs(v,x);
            sum[x]+=sum[v];
        }
    }
}
void dp(long long x,long long fa=-1)
{
    if(f[x]>f[ans])
    {
        ans=x;
    }
    for(auto v:mp[x])
    {
        if(v!=fa)
        {
            f[v]=f[x]+(sum[1]-sum[v])-sum[v];
            dp(v,x);
        }
    }
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs(1);
    dp(1);
    printf("%lld",ans);
    return 0;
}
